36:let tmpDir: string;
38:function makeTmpDir(): string {
39:  tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), 'oculus-test-'));
40:  return tmpDir;
41:}
43:function cleanupTmpDir(): void {
44:  if (tmpDir) {
45:    try {
46:      fs.rmSync(tmpDir, { recursive: true, force: true });
47:    } catch { /* ignore */ }
