1:/**
2: * nsg status — guild status.
3: *
4: * A framework command. Shows guild identity, framework version, and installed plugins
5: * separated into apparatuses (running infrastructure) and kits (passive capabilities).
6: * Domain-specific status (writ counts, session history, clock state) belongs
7: * to plugins, not here.
8: *
9: * Requires a booted guild — prints a friendly error if run outside one.
10: */
12:import { tool } from '@shardworks/tools-apparatus';
13:import { VERSION, readGuildConfig, guild } from '@shardworks/nexus-core';
14:import { z } from 'zod';
16:export default tool({
17:  name: 'status',
18:  description: 'Show guild identity and installed plugin summary',
19:  callableBy: ['patron'],
20:  params: {
21:    json: z.boolean().optional().describe('Output as JSON'),
22:  },
23:  handler: async (params) => {
24:    let g;
25:    try {
26:      g = guild();
27:    } catch {
28:      throw new Error('Not inside a guild. Run `nsg init` to create one, or use --guild-root to specify the path.');
29:    }
31:    const { home } = g;
32:    const config = readGuildConfig(home);
33:    const failed = g.failedPlugins();
35:    // Note: at status time we don't load/start plugins — we just report what's
36:    // declared in guild.json. Type discrimination (kit vs apparatus) requires
37:    // loading the modules, which is deferred to avoid startup cost for status.
38:    const result = {
39:      guild:         config.name,
40:      nexus:         VERSION,
41:      home,
42:      model:         config.settings?.model ?? '(not set)',
43:      plugins:       [...config.plugins].sort(),
44:      failedPlugins: failed,
45:    };
47:    if (params.json) {
48:      return result;
49:    }
51:    const lines = [
52:      `Guild:    ${result.guild}`,
53:      `Nexus:    ${result.nexus}`,
54:      `Home:     ${result.home}`,
55:      `Model:    ${result.model}`,
56:      `Plugins:  ${result.plugins.length > 0 ? result.plugins.join(', ') : '(none)'}`,
57:    ];
59:    if (failed.length > 0) {
60:      lines.push('');
61:      lines.push('Failed plugins:');
62:      for (const f of failed) {
63:        lines.push(`  ${f.id}: ${f.reason}`);
64:      }
65:    }
67:    return lines.join('\n');
68:  },
69:});

