4:/** A custom event declaration in guild.json clockworks.events. */
5:export interface EventDeclaration {
6:  /** Human-readable description of what this event means. */
7:  description?: string;
8:  /** Optional payload schema hint (not enforced in Phase 1). */
9:  schema?: Record<string, string>;
10:}
13:/** A standing order — a registered response to an event. */
14:export type StandingOrder =
15:  | { on: string; run: string }
16:  | { on: string; summon: string; prompt?: string }
17:  | { on: string; brief: string };
19:/** The clockworks configuration block in guild.json. */
20:export interface ClockworksConfig {
21:  /** Custom event declarations. */
22:  events?: Record<string, EventDeclaration>;
23:  /** Standing orders — event → action mappings. */
24:  standingOrders?: StandingOrder[];
25:}
27:/** Guild-level settings — operational flags and preferences. */
28:export interface GuildSettings {
29:  /**
30:   * Default LLM model for anima sessions (e.g. 'sonnet', 'opus').
31:   * Replaces the top-level `model` field from GuildConfig V1.
32:   */
33:  model?: string;
34:  /**
35:   * Automatically apply pending database migrations when the Books are opened.
36:   * Defaults to `true` when not specified. Set to `false` to require explicit
37:   * migration via `nsg guild upgrade-books`.
38:   */
39:  autoMigrate?: boolean;
40:}
42:/**
43: * Guild configuration.
44: *
45: * The plugin-centric model: plugins are npm packages; capabilities (tools, engines,
46: * training content) are declared by plugins and discovered dynamically at runtime.
47: * Framework-level keys (`name`, `nexus`, `plugins`, `settings`) are defined here;
48: * all other top-level keys are plugin configuration sections, keyed by plugin id.
49: */
50:export interface GuildConfig {
51:  /** Guild name — used as the guildhall npm package name. */
52:  name: string;
53:  /** Installed Nexus framework version. */
54:  nexus: string;
55:  /** Installed plugin ids (derived from npm package names). Always present; starts empty. */
56:  plugins: string[];
57:  /** Clockworks configuration — events, standing orders. */
58:  clockworks?: ClockworksConfig;
59:  /** Guild-level settings — operational flags and preferences. Includes default model. */
60:  settings?: GuildSettings;
61:}
63:/**
64: * Create the default guild.json content for a new guild.
65: * All collections start empty. The default model is stored in settings.
66: */
67:export function createInitialGuildConfig(name: string, nexusVersion: string, model: string): GuildConfig {
68:  return {
69:    name,
70:    nexus: nexusVersion,
71:    plugins: [],
72:    settings: { model },
73:  };
74:}
76:/** Read and parse guild.json from the guild root. */
77:export function readGuildConfig(home: string): GuildConfig {
78:  const configFile = guildConfigPath(home);
79:  return JSON.parse(fs.readFileSync(configFile, 'utf-8')) as GuildConfig;
80:}
82:/** Write guild.json to the guild root. */
83:export function writeGuildConfig(home: string, config: GuildConfig): void {
84:  const configFile = guildConfigPath(home);
85:  fs.writeFileSync(configFile, JSON.stringify(config, null, 2) + '\n');
86:}
88:/** Resolve the path to guild.json in the guild root. */
89:export function guildConfigPath(home: string): string {
90:  return path.join(home, 'guild.json');
91:}

