167:      writeGuildConfig(guildRoot, config);
168:    },
170:    guildConfig() {
171:      return config;
172:    },
174:    kits()          { return [...kits]; },
175:    apparatuses()   { return [...orderedApparatuses]; },
176:    failedPlugins() { return [...allFailures]; },
