60	export async function createGuild(root?: string): Promise<Guild> {
61	  const guildRoot = root ?? findGuildRoot();
62	  const config = readGuildConfig(guildRoot);
63	
64	  const kits:        LoadedKit[]        = [];
65	  const apparatuses: LoadedApparatus[]  = [];
66	  const eventHandlers: EventHandlerMap = new Map();
67	
68	  // ── Load phase ─────────────────────────────────────────────────────
69	
70	  for (const pluginId of config.plugins) {
71	    const packageName = resolvePackageNameForPluginId(guildRoot, pluginId);
72	    if (!packageName) {
73	      console.warn(`[arbor] No package found in package.json for plugin "${pluginId}" — skipping`);
74	      continue;
75	    }
76	
77	    const { version } = readGuildPackageJson(guildRoot, packageName);
78	
79	    try {
80	      const entryPath = resolveGuildPackageEntry(guildRoot, packageName);
81	      const mod = await import(entryPath) as { default: unknown };
82	      const raw = mod.default;
83	
84	      if (isApparatus(raw)) {
85	        apparatuses.push({ packageName, id: pluginId, version, apparatus: raw.apparatus });
86	      } else if (isKit(raw)) {
87	        kits.push({ packageName, id: pluginId, version, kit: raw.kit });
88	      } else {
89	        console.warn(
90	          `[arbor] Plugin "${packageName}" does not export a kit or apparatus — skipping. ` +
91	          `Plugins must export { kit: ... } or { apparatus: ... }.`,
92	        );
93	      }
94	    } catch (err) {
95	      const message = err instanceof Error ? err.message : String(err);
96	      console.warn(`[arbor] Failed to load plugin "${packageName}": ${message}`);
97	    }
98	  }
99	
100	  // ── Validation phase ───────────────────────────────────────────────
101	
102	  const allFailures: FailedPlugin[] = [];
103	
104	  const rootFailures = validateRequires(kits, apparatuses);
105	  allFailures.push(...rootFailures);
106	
107	  // Remove plugins that transitively depend on failed ones
108	  if (rootFailures.length > 0) {
109	    const filtered = filterFailedPlugins(kits, apparatuses, rootFailures);
110	    kits.length = 0;
111	    kits.push(...filtered.kits);
112	    apparatuses.length = 0;
113	    apparatuses.push(...filtered.apparatuses);
114	    allFailures.push(...filtered.cascaded);
115	
116	    for (const f of allFailures) {
117	      console.warn(`[arbor] ${f.reason}`);
118	    }
119	  }
120	
121	  // ── Startup warnings ───────────────────────────────────────────────
122	
123	  for (const warning of collectStartupWarnings(kits, apparatuses)) {
124	    console.warn(warning);
125	  }
126	
127	  // ── Start phase ────────────────────────────────────────────────────
128	
129	  const orderedApparatuses = topoSort(apparatuses);
130	  const provides = new Map<string, unknown>();
131	
132	  // Wire guild singleton before any apparatus starts so start() methods
133	  // can call guild(). The provides Map is populated progressively as each
134	  // apparatus starts; dependency ordering guarantees declared deps are
135	  // available.
136	
137	  const guildInstance: Guild = {
138	    home: guildRoot,
139	
140	    apparatus<T>(name: string): T {
141	      const p = provides.get(name);
142	      if (p === undefined) {
143	        throw new Error(
144	          `[guild] apparatus("${name}") is not available. ` +
145	          `No loaded apparatus provides this id. Check guild.json plugins list.`,
146	        );
147	      }
148	      return p as T;
149	    },
150	
151	    config<T = Record<string, unknown>>(pluginId: string): T {
152	      // GuildConfig types only the framework-level keys (name, nexus, plugins, etc.).
153	      // Plugin-specific config sections (e.g. "animator", "stacks") are additional
154	      // top-level keys in guild.json that GuildConfig doesn't model. The cast is safe
155	      // because guild.json is a plain JSON object — all keys are accessible at runtime.
156	      // Plugins can use module augmentation on GuildConfig to get typed access; this
157	      // generic path remains the untyped fallback.
158	      const cfg = config as unknown as Record<string, unknown>;
159	      return (cfg[pluginId] ?? {}) as T;
160	    },
161	
162	    writeConfig<T = Record<string, unknown>>(pluginId: string, value: T): void {
163	      // Update the in-memory config so subsequent reads reflect the change,
164	      // then persist to disk. The cast is the same pattern as config() above.
165	      const cfg = config as unknown as Record<string, unknown>;
166	      cfg[pluginId] = value;
167	      writeGuildConfig(guildRoot, config);
168	    },
169	
170	    guildConfig() {
171	      return config;
172	    },
